  register() {
    this.errorMessage = '';

    // בדיקת שדות חובה
    if (!this.firstName || !this.lastName || !this.email || !this.password) {
      this.errorMessage = 'אנא מלאי את כל השדות הנדרשים';
      return;
    }

    // בדיקת התאמת סיסמאות רק בלחיצה על הכפתור
    if (this.password !== this.confirmPassword) {
      this.errorMessage = 'הסיסמאות אינן תואמות';
      return;
    }

    // חוזק סיסמה מינימלי
    if (this.passwordStrength <6) {
      alert(this.passwordStrength)
      this.errorMessage = 'הסיסמה חלשה מדי';
      return;
    }

    // קריאה ל-AuthorService להרשמה
    this.authorService.register({
      firstName: this.firstName,
      lastName: this.lastName,
      email: this.email,
      phone: this.phone,
      password: this.password
    }).subscribe({
      next: (res) => {
        console.log('ההרשמה הצליחה:', res);
        this.visibleRegister = false;
        this.resetForm();
      },
      error: (err) => {
        console.error('שגיאה בהרשמה:', err);
        this.errorMessage = err.error?.message || 'שגיאה בהרשמה';
        console.error('Full Error Object:', err);

        // 1. בדיקה אם השרת החזיר הודעה ספציפית בתוך אובייקט error
        if (err.error && err.error.message) {
          this.errorMessage = err.error.message;
        }
        // 2. בדיקה אם השרת החזיר שגיאות ולידציה של ASP.NET (מבנה של errors: { field: [messages] })
        else if (err.error && err.error.errors) {
          const errorDetails = err.error.errors;
          // לוקחים את השגיאה הראשונה שנמצאה ומציגים אותה
          const firstErrorKey = Object.keys(errorDetails)[0];
          this.errorMessage = errorDetails[firstErrorKey][0];
        }
        // 3. בדיקה אם ה-error עצמו הוא מחרוזת טקסט
        else if (typeof err.error === 'string') {
          this.errorMessage = err.error;
        }
        // 4. ברירת מחדל אם לא הצלחנו לחלץ הודעה ספציפית
        else {
          this.errorMessage = 'אירעה שגיאה בביצוע הפעולה, אנא נסו שנית';
        }

      }
    });
  }

  resetForm() {
    this.firstName = '';
    this.lastName = '';
    this.email = '';
    this.phone = '';
    this.password = '';
    this.confirmPassword = '';
    this.errorMessage = '';
    this.passwordStrength = 0;
  }


  logout() {
    const token = localStorage.getItem('authToken');
    if (token) {
      localStorage.removeItem('authToken');


      console.log('User logged out, localStorage cleared!');
      alert('You have been logged out.');
      this.reset();
      window.location.reload();
    }
    else {
      alert("אין משתמש מחובר")
      console.log('No user is currently logged in.');
    }
  }
  reset() {
    this.email = '';
    this.password = '';
    this.firstName = '';
    this.lastName = '';
    this.phone = '';
    console.log('Fields cleared!');
  }
  showLogin() {
    this.errorMessage = '';
    this.visibleLogin = true;
  }

  showRegister() {
    this.errorMessage = '';
    this.visibleRegister = true;
  }
}
